78	                return Self::dummy();
79	            }
80	        };
81	
82	        let code_size = image.code.len();
83	        let data_size = image.data.len();
84	        let global_count = image.global_count as usize;
85	        let globals_base = code_size + data_size;
86	        let globals_size = global_count * WORD;
87	        let call_stack_base = globals_base + globals_size;
88	        let call_stack_size = 256 * WORD;
89	        let eval_stack_base = call_stack_base + call_stack_size;
90	        let eval_stack_size = 256 * WORD;
91	        let heap_base = eval_stack_base + eval_stack_size;
92	        let heap_size = 4096 * WORD;
93	        let total = heap_base + heap_size;
94	
95	        let mut mem = vec![0u8; total];
96	        mem[..code_size].copy_from_slice(&image.code);
97	        mem[code_size..code_size + data_size].copy_from_slice(&image.data);
98	
99	        let has_line_numbers = basic_source.lines().any(|line| {
100	            let trimmed = line.trim_start();
101	            trimmed.chars().next().is_some_and(|c| c.is_ascii_digit())
102	        });
103	
104	        let mut stdin_buf = Vec::new();
105	        for b in basic_source.bytes() {
106	            stdin_buf.push(b);
107	        }
108	        if interactive {
109	            // Interactive mode: load source and start RUN, but leave the stream
110	            // open so the user can supply INPUT bytes (and eventually type BYE).
111	            if has_line_numbers {
112	                stdin_buf.extend_from_slice(b"RUN\n");
113	            } else {
114	                stdin_buf.push(b'\n');
115	            }
116	        } else if has_line_numbers {
117	            stdin_buf.extend_from_slice(b"RUN\nBYE\n");
118	            stdin_buf.push(0x04);
119	        } else {
120	            stdin_buf.push(b'\n');
121	            stdin_buf.push(0x04);
122	        }
123	
124	        Session {
125	            mem,
126	            pc: image.entry_point as usize,
127	            esp: eval_stack_base,
128	            csp: call_stack_base,
129	            fp_vm: call_stack_base,
130	            gp: globals_base,
131	            hp: heap_base,
132	            code_size,
133	            eval_stack_base,
134	            heap_base,
135	            status: 0,
136	            trap_code: 0,
137	            instruction_count: 0,
138	            stdin_buf,
139	            stdin_pos: 0,
140	            stdout_buf: String::new(),
141	            interactive,
142	            awaiting_input: false,
143	        }
144	    }
145	
146	    pub fn is_awaiting_input(&self) -> bool {
147	        self.awaiting_input
148	    }
149	
150	    /// Append a line of user input (a newline is appended automatically) and
151	    /// resume execution. No-op outside interactive mode.
152	    pub fn feed_input(&mut self, line: &str) {
153	        if !self.interactive {
154	            return;
155	        }
156	        for b in line.bytes() {
157	            self.stdin_buf.push(b);
158	        }
159	        if !line.ends_with('\n') {
160	            self.stdin_buf.push(b'\n');
161	        }
162	        self.awaiting_input = false;
163	    }
164	
165	    pub fn tick(&mut self) -> TickResult {
166	        if self.status != 0 {
167	            return TickResult { done: true };
168	        }
169	        if self.awaiting_input {
170	            return TickResult { done: false };
171	        }
172	
173	        let budget = BATCH_SIZE;
174	
175	        let mut ran = 0u64;
176	        while self.status == 0 && !self.awaiting_input && ran < budget {
177	            let op_byte = self.fetch_u8();
178	            self.execute(op_byte);
179	            if self.awaiting_input {
180	                // GETC pulled an empty interactive stream and rewound PC.
181	                // Don't count this as an executed instruction.
182	                break;
183	            }
184	            self.instruction_count += 1;
185	            ran += 1;
186	        }
187	
188	        TickResult {
189	            done: self.status != 0,
190	        }
191	    }
192	
193	    pub fn is_done(&self) -> bool {
194	        self.status != 0
195	    }
196	
197	    pub fn is_halted(&self) -> bool {
198	        self.status == 1
199	    }
