214	        self.stdout_buf.chars().filter(|&c| c != '>').collect()
215	    }
216	
217	    // --- memory access ---
218	
219	    fn read_word(&self, addr: usize) -> i32 {
220	        if addr + 2 >= self.mem.len() {
221	            return 0;
222	        }
223	        let lo = self.mem[addr] as i32;
224	        let mid = self.mem[addr + 1] as i32;
225	        let hi = self.mem[addr + 2] as i32;
226	        sign_extend_24(lo | (mid << 8) | (hi << 16))
227	    }
228	
229	    fn write_word(&mut self, addr: usize, val: i32) {
230	        let v = val & MASK24;
231	        if addr + 2 >= self.mem.len() {
232	            self.trap(2);
233	            return;
234	        }
235	        self.mem[addr] = v as u8;
236	        self.mem[addr + 1] = (v >> 8) as u8;
237	        self.mem[addr + 2] = (v >> 16) as u8;
238	    }
239	
240	    fn read_byte(&self, addr: usize) -> i32 {
241	        if addr >= self.mem.len() {
242	            0
243	        } else {
244	            self.mem[addr] as i32
245	        }
246	    }
247	
248	    fn write_byte(&mut self, addr: usize, val: i32) {
249	        if addr >= self.mem.len() {
250	            self.trap(2);
251	            return;
252	        }
253	        self.mem[addr] = val as u8;
254	    }
255	
256	    // --- fetch ---
257	
258	    fn fetch_u8(&mut self) -> u8 {
259	        let v = if self.pc < self.code_size {
260	            self.mem[self.pc]
261	        } else {
262	            0
263	        };
264	        self.pc += 1;
265	        v
266	    }
267	
268	    fn fetch_i8(&mut self) -> i32 {
269	        self.fetch_u8() as i8 as i32
270	    }
271	
272	    fn fetch_u24(&mut self) -> u32 {
273	        let lo = self.fetch_u8() as u32;
274	        let mid = self.fetch_u8() as u32;
275	        let hi = self.fetch_u8() as u32;
276	        lo | (mid << 8) | (hi << 16)
277	    }
278	
279	    // --- eval stack ---
280	
281	    fn push_eval(&mut self, val: i32) {
282	        if self.esp >= self.heap_base {
283	            self.trap(2);
284	            return;
285	        }
286	        self.write_word(self.esp, val);
287	        self.esp += WORD;
288	    }
289	
290	    fn pop_eval(&mut self) -> i32 {
291	        if self.esp <= self.eval_stack_base {
292	            self.trap(3);
293	            return 0;
294	        }
295	        self.esp -= WORD;
296	        self.read_word(self.esp)
297	    }
298	
299	    fn peek_eval(&self) -> i32 {
300	        if self.esp <= self.eval_stack_base {
301	            0
302	        } else {
303	            self.read_word(self.esp - WORD)
304	        }
305	    }
306	
307	    fn trap(&mut self, code: u8) {
308	        self.status = 2;
309	        self.trap_code = code;
310	    }
311	
312	    fn follow_static_links(&self, depth: usize) -> usize {
313	        let mut frame = self.fp_vm;
314	        for _ in 0..depth {
315	            frame = self.read_word(frame + 2 * WORD) as usize;
316	        }
317	        frame
318	    }
319	
320	    // --- execute ---
321	
322	    fn execute(&mut self, op: u8) {
323	        match op {
324	            0x00 => {
325	                self.status = 1;
326	            }
327	            0x01 => {
328	                let v = self.fetch_u24() as i32;
329	                self.push_eval(sign_extend_24(v));
330	            }
331	            0x02 => {
332	                let v = self.fetch_i8();
333	                self.push_eval(wrap24(v));
334	            }
335	            0x03 => {
336	                let v = self.peek_eval();
337	                self.push_eval(v);
338	            }
339	            0x04 => {
340	                self.pop_eval();
341	            }
342	            0x05 => {
343	                let b = self.pop_eval();
344	                let a = self.pop_eval();
345	                self.push_eval(b);
346	                self.push_eval(a);
347	            }
348	            0x06 => {
349	                let b = self.pop_eval();
350	                let a = self.pop_eval();
351	                self.push_eval(a);
352	                self.push_eval(b);
353	                self.push_eval(a);
354	            }
355	            0x10 => {
356	                let b = self.pop_eval();
357	                let a = self.pop_eval();
358	                self.push_eval(wrap24(a.wrapping_add(b)));
359	            }
360	            0x11 => {
361	                let b = self.pop_eval();
362	                let a = self.pop_eval();
363	                self.push_eval(wrap24(a.wrapping_sub(b)));
364	            }
365	            0x12 => {
366	                let b = self.pop_eval();
367	                let a = self.pop_eval();
368	                self.push_eval(wrap24(a.wrapping_mul(b)));
369	            }
370	            0x13 => {
371	                let b = self.pop_eval();
372	                let a = self.pop_eval();
373	                if b == 0 {
374	                    self.trap(1);
375	                    return;
376	                }
377	                self.push_eval(wrap24(a / b));
378	            }
379	            0x14 => {
380	                let b = self.pop_eval();
381	                let a = self.pop_eval();
382	                if b == 0 {
383	                    self.trap(1);
384	                    return;
385	                }
386	                self.push_eval(wrap24(a % b));
387	            }
388	            0x15 => {
389	                let a = self.pop_eval();
390	                self.push_eval(wrap24(-a));
391	            }
392	            0x16 => {
393	                let b = self.pop_eval();
394	                let a = self.pop_eval();
395	                self.push_eval(wrap24(a & b));
396	            }
397	            0x17 => {
398	                let b = self.pop_eval();
399	                let a = self.pop_eval();
400	                self.push_eval(wrap24(a | b));
401	            }
402	            0x18 => {
403	                let b = self.pop_eval();
404	                let a = self.pop_eval();
405	                self.push_eval(wrap24(a ^ b));
406	            }
407	            0x19 => {
408	                let a = self.pop_eval();
409	                self.push_eval(wrap24(!a));
410	            }
411	            0x1A => {
412	                let n = self.pop_eval();
413	                let a = self.pop_eval();
414	                self.push_eval(wrap24(a << (n & 0x1F)));
415	            }
416	            0x1B => {
417	                let n = self.pop_eval();
418	                let a = self.pop_eval();
419	                self.push_eval(wrap24(a >> (n & 0x1F)));
420	            }
421	            0x20 => {
422	                let b = self.pop_eval();
423	                let a = self.pop_eval();
424	                self.push_eval(if a == b { 1 } else { 0 });
425	            }
426	            0x21 => {
427	                let b = self.pop_eval();
428	                let a = self.pop_eval();
429	                self.push_eval(if a != b { 1 } else { 0 });
430	            }
431	            0x22 => {
432	                let b = self.pop_eval();
433	                let a = self.pop_eval();
434	                self.push_eval(if a < b { 1 } else { 0 });
435	            }
436	            0x23 => {
437	                let b = self.pop_eval();
438	                let a = self.pop_eval();
439	                self.push_eval(if a <= b { 1 } else { 0 });
440	            }
441	            0x24 => {
442	                let b = self.pop_eval();
443	                let a = self.pop_eval();
444	                self.push_eval(if a > b { 1 } else { 0 });
445	            }
446	            0x25 => {
447	                let b = self.pop_eval();
448	                let a = self.pop_eval();
449	                self.push_eval(if a >= b { 1 } else { 0 });
450	            }
451	            0x30 => {
452	                let addr = self.fetch_u24() as usize;
453	                self.pc = addr;
454	            }
455	            0x31 => {
456	                let addr = self.fetch_u24() as usize;
457	                let flag = self.pop_eval();
458	                if flag == 0 {
459	                    self.pc = addr;
460	                }
461	            }
462	            0x32 => {
463	                let addr = self.fetch_u24() as usize;
464	                let flag = self.pop_eval();
465	                if flag != 0 {
466	                    self.pc = addr;
467	                }
468	            }
469	            0x33 => {
470	                let addr = self.fetch_u24() as usize;
471	                self.write_word(self.csp, self.pc as i32);
472	                self.write_word(self.csp + WORD, self.fp_vm as i32);
473	                self.write_word(self.csp + 2 * WORD, self.fp_vm as i32);
474	                self.write_word(self.csp + 3 * WORD, self.esp as i32);
475	                self.csp += 4 * WORD;
476	                self.pc = addr;
477	            }
478	            0x34 => {
479	                let nargs = self.fetch_u8() as usize;
480	                let return_pc = self.read_word(self.fp_vm) as usize;
481	                let dynamic_link = self.read_word(self.fp_vm + WORD) as usize;
482	                let saved_esp = self.read_word(self.fp_vm + 3 * WORD) as usize;
483	                let has_return = self.esp > saved_esp;
484	                let return_val = if has_return {
485	                    Some(self.pop_eval())
486	                } else {
487	                    None
488	                };
489	                self.csp = self.fp_vm;
490	                self.fp_vm = dynamic_link;
491	                self.esp = saved_esp - nargs * WORD;
492	                if let Some(rv) = return_val {
493	                    self.push_eval(rv);
494	                }
495	                self.pc = return_pc;
496	            }
497	            0x35 => {
498	                let depth = self.fetch_u8();
499	                let addr = self.fetch_u24() as usize;
500	                let mut sl = self.fp_vm;
501	                for _ in 0..depth {
502	                    sl = self.read_word(sl + 2 * WORD) as usize;
503	                }
504	                self.write_word(self.csp, self.pc as i32);
505	                self.write_word(self.csp + WORD, self.fp_vm as i32);
506	                self.write_word(self.csp + 2 * WORD, sl as i32);
507	                self.write_word(self.csp + 3 * WORD, self.esp as i32);
508	                self.csp += 4 * WORD;
509	                self.pc = addr;
510	            }
511	            0x36 => {
512	                let code = self.fetch_u8();
513	                self.trap(code);
514	            }
515	            0x40 => {
516	                let nlocals = self.fetch_u8() as usize;
517	                self.fp_vm = self.csp - 4 * WORD;
518	                for _ in 0..nlocals {
519	                    self.write_word(self.csp, 0);
520	                    self.csp += WORD;
521	                }
522	            }
523	            0x41 => {
524	                self.csp = self.fp_vm + 4 * WORD;
525	            }
526	            0x42 => {
527	                let off = self.fetch_u8() as usize;
528	                let addr = self.fp_vm + 4 * WORD + off * WORD;
529	                self.push_eval(self.read_word(addr));
530	            }
531	            0x43 => {
532	                let off = self.fetch_u8() as usize;
533	                let val = self.pop_eval();
534	                let addr = self.fp_vm + 4 * WORD + off * WORD;
535	                self.write_word(addr, val);
536	            }
537	            0x44 => {
538	                let off = self.fetch_u24() as usize;
539	                let addr = self.gp + off * WORD;
540	                self.push_eval(self.read_word(addr));
541	            }
542	            0x45 => {
543	                let off = self.fetch_u24() as usize;
544	                let val = self.pop_eval();
545	                let addr = self.gp + off * WORD;
546	                self.write_word(addr, val);
547	            }
548	            0x46 => {
549	                let off = self.fetch_u8() as usize;
550	                let addr = self.fp_vm + 4 * WORD + off * WORD;
551	                self.push_eval(addr as i32);
552	            }
553	            0x47 => {
554	                let off = self.fetch_u24() as usize;
555	                let addr = self.gp + off * WORD;
556	                self.push_eval(addr as i32);
557	            }
558	            0x48 => {
559	                let idx = self.fetch_u8() as usize;
560	                let saved_esp = self.read_word(self.fp_vm + 3 * WORD) as usize;
561	                let addr = saved_esp - (idx + 1) * WORD;
562	                self.push_eval(self.read_word(addr));
563	            }
564	            0x49 => {
565	                let idx = self.fetch_u8() as usize;
566	                let val = self.pop_eval();
567	                let saved_esp = self.read_word(self.fp_vm + 3 * WORD) as usize;
568	                let addr = saved_esp - (idx + 1) * WORD;
569	                self.write_word(addr, val);
570	            }
571	            0x4A => {
572	                let depth = self.fetch_u8() as usize;
573	                let off = self.fetch_u8() as usize;
574	                let frame = self.follow_static_links(depth);
575	                let addr = frame + 4 * WORD + off * WORD;
576	                self.push_eval(self.read_word(addr));
577	            }
578	            0x4B => {
579	                let depth = self.fetch_u8() as usize;
580	                let off = self.fetch_u8() as usize;
581	                let val = self.pop_eval();
582	                let frame = self.follow_static_links(depth);
583	                let addr = frame + 4 * WORD + off * WORD;
584	                self.write_word(addr, val);
585	            }
586	            0x50 => {
587	                let addr = self.pop_eval();
588	                if addr == 0 {
589	                    self.trap(6);
590	                    return;
591	                }
592	                self.push_eval(self.read_word(addr as usize));
593	            }
594	            0x51 => {
595	                let addr = self.pop_eval();
596	                let val = self.pop_eval();
597	                if addr == 0 {
598	                    self.trap(6);
599	                    return;
600	                }
601	                self.write_word(addr as usize, val);
602	            }
603	            0x52 => {
604	                let addr = self.pop_eval();
605	                if addr == 0 {
606	                    self.trap(6);
607	                    return;
608	                }
609	                self.push_eval(self.read_byte(addr as usize));
610	            }
611	            0x53 => {
612	                let addr = self.pop_eval();
613	                let val = self.pop_eval();
614	                if addr == 0 {
615	                    self.trap(6);
616	                    return;
617	                }
618	                self.write_byte(addr as usize, val);
619	            }
620	            0x60 => {
621	                let id = self.fetch_u8();
622	                self.sys_call(id);
623	            }
624	            0x70 => {
625	                let len = self.pop_eval() as usize;
626	                let dst = self.pop_eval() as usize;
627	                let src = self.pop_eval() as usize;
628	                if len > 0 {
629	                    if src < dst {
630	                        for i in (0..len).rev() {
631	                            let b = self.read_byte(src + i);
632	                            self.write_byte(dst + i, b);
633	                        }
634	                    } else {
635	                        for i in 0..len {
636	                            let b = self.read_byte(src + i);
637	                            self.write_byte(dst + i, b);
638	                        }
639	                    }
640	                }
641	            }
642	            0x71 => {
643	                let len = self.pop_eval() as usize;
644	                let val = self.pop_eval();
645	                let dst = self.pop_eval() as usize;
646	                if len > 0 {
647	                    for i in 0..len {
648	                        self.write_byte(dst + i, val);
649	                    }
650	                }
651	            }
652	            0x72 => {
653	                let len = self.pop_eval() as usize;
654	                let b = self.pop_eval() as usize;
655	                let a = self.pop_eval() as usize;
656	                let mut result: i32 = 0;
657	                for i in 0..len {
658	                    let ba = self.read_byte(a + i) & 0xFF;
659	                    let bb = self.read_byte(b + i) & 0xFF;
660	                    if ba != bb {
661	                        result = if ba < bb { -1 } else { 1 };
662	                        break;
663	                    }
664	                }
665	                self.push_eval(result);
666	            }
667	            0x73 => {
668	                let addr = self.pop_eval() as usize;
669	                self.pc = addr;
670	            }
671	            0x74 => {
672	                let _ = self.fetch_u8();
673	                let _ = self.fetch_u8();
674	                self.trap(4);
675	            }
676	            0x75 | 0x76 => {
677	                let _ = self.fetch_u8();
678	                let _ = self.fetch_u8();
679	                self.trap(4);
680	            }
681	            _ => {
682	                self.trap(4);
683	            }
684	        }
685	    }
686	
687	    fn sys_call(&mut self, id: u8) {
688	        match id {
689	            0 => {
690	                self.status = 1;
691	            }
692	            1 => {
693	                let ch = self.pop_eval() as u8;
694	                self.stdout_buf.push(ch as char);
695	            }
696	            2 => {
697	                if self.stdin_pos < self.stdin_buf.len() {
698	                    let c = self.stdin_buf[self.stdin_pos];
699	                    self.stdin_pos += 1;
700	                    self.push_eval(c as i32);
701	                } else if self.interactive {
702	                    // Pause execution until the host calls feed_input().
703	                    // Rewind PC past the SYSCALL opcode (0x60) and its 1-byte
704	                    // id so the syscall re-executes on resume.
705	                    self.pc -= 2;
706	                    self.awaiting_input = true;
707	                } else {
708	                    self.push_eval(-1);
709	                }
710	            }
711	            3 => {
712	                self.pop_eval();
713	            }
714	            4 => {
715	                let size = self.pop_eval() as usize;
716	                let ptr = self.hp;
717	                self.hp += size;
718	                if self.hp > self.mem.len() {
719	                    self.mem.resize(self.hp, 0);
720	                }
721	                self.push_eval(ptr as i32);
722	            }
723	            5 => {
724	                self.pop_eval();
725	            }
726	            6 => {
727	                self.push_eval(0);
728	            }
729	            7 => {
730	                self.pop_eval();
731	            }
732	            8 => {}
733	            _ => {
734	                self.trap(4);
735	            }
736	        }
737	    }
738	}
739	
740	pub struct TickResult {
741	    pub done: bool,
742	}
743	
744	#[cfg(test)]
745	mod tests {
746	    use super::*;
747	
748	    fn run_to_done(src: &str) -> Session {
749	        let mut s = Session::new(src);
750	        for _ in 0..1000 {
751	            let r = s.tick();
752	            if r.done {
753	                break;
754	            }
755	        }
756	        s
757	    }
