801	        // Now resume — program should print 14 then return to REPL prompt and
802	        // block waiting for the next interactive input. Send BYE to halt.
803	        for _ in 0..200_000 {
804	            let r = s.tick();
805	            if r.done || s.is_awaiting_input() {
806	                break;
807	            }
808	        }
