---cargo---
[package]
name = "pa24r"
version = "0.1.0"
edition = "2024"

[dependencies]
---lib top---
// pa24r — P-Code Assembler for COR24

pub mod lexer;

// .p24 header constants
pub const P24_MAGIC: [u8; 4] = [0x50, 0x32, 0x34, 0x00]; // "P24\0"
pub const P24_VERSION: u8 = 1;
pub const P24_VERSION_2: u8 = 2;
pub const P24_HEADER_SIZE: usize = 18;

/// Encoding format for p-code instructions.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Encoding {
    /// 1 byte: [op]
    None,
    /// 2 bytes: [op, imm8]
    Imm8,
    /// 4 bytes: [op, lo, mid, hi]
    Imm24,
    /// 5 bytes: [op, d8, lo, mid, hi]
    D8A24,
    /// 3 bytes: [op, d8, o8]
    D8O8,
    /// 3 bytes: [op, lo, hi] — 16-bit LE operand
    Imm16,
}

impl Encoding {
    /// Total instruction size in bytes (including opcode byte).
    pub const fn size(self) -> usize {
        match self {
            Encoding::None => 1,
            Encoding::Imm8 => 2,
            Encoding::Imm24 => 4,
            Encoding::D8A24 => 5,
            Encoding::D8O8 => 3,
            Encoding::Imm16 => 3,
        }
    }
}

/// P-code opcodes. Values match pvm.s ground truth.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[repr(u8)]
pub enum Opcode {
    // Stack operations (0x00-0x06)
    Halt = 0x00,
    Push = 0x01,
    PushS = 0x02,
    Dup = 0x03,
    Drop = 0x04,
    Swap = 0x05,
    Over = 0x06,

    // Arithmetic (0x10-0x15)
    Add = 0x10,
    Sub = 0x11,
    Mul = 0x12,
    Div = 0x13,
    Mod = 0x14,
    Neg = 0x15,

    // Logic (0x16-0x1B)
    And = 0x16,
    Or = 0x17,
    Xor = 0x18,
    Not = 0x19,
    Shl = 0x1A,
    Shr = 0x1B,

    // Comparison (0x20-0x25)
    Eq = 0x20,
    Ne = 0x21,
    Lt = 0x22,
    Le = 0x23,
    Gt = 0x24,
    Ge = 0x25,

    // Control flow (0x30-0x36)
    Jmp = 0x30,

