    /// 4 bytes: [op, lo, mid, hi]
    Imm24,
    /// 5 bytes: [op, d8, lo, mid, hi]
    D8A24,
    /// 3 bytes: [op, d8, o8]
    D8O8,
    /// 3 bytes: [op, lo, hi] — 16-bit LE operand
    Imm16,
}

impl Encoding {
    /// Total instruction size in bytes (including opcode byte).
    pub const fn size(self) -> usize {
        match self {
            Encoding::None => 1,
            Encoding::Imm8 => 2,
            Encoding::Imm24 => 4,
            Encoding::D8A24 => 5,
            Encoding::D8O8 => 3,
            Encoding::Imm16 => 3,
        }
    }
}

