210	
211	    pub fn trap(&mut self, code: u8) {
212	        self.status = 2;
213	        self.trap_code = code;
214	    }
215	
216	    pub fn run(&mut self) {
217	        while self.status == 0 {
218	            if self.max_instructions > 0 && self.instruction_count >= self.max_instructions {
219	                eprintln!(
220	                    "pv24t: instruction limit reached ({} instructions)",
221	                    self.max_instructions
222	                );
223	                self.status = 1;
224	                break;
225	            }
226	            self.step_one();
227	        }
228	
229	        // Print trap message (matches pvm.s behavior)
230	        if self.status == 2 {
231	            let stdout = io::stdout();
232	            let mut out = stdout.lock();
233	            let _ = writeln!(out, "TRAP {}", self.trap_code);
234	        }
235	    }
236	
237	    /// Execute exactly one instruction. Increments instruction_count.
238	    /// Used by the debugger for step-by-step execution.
239	    pub fn step_one(&mut self) {
240	        if self.status != 0 {
241	            return;
242	        }
243	        let instr_pc = self.pc;
244	        let op_byte = self.fetch_u8();
245	
246	        let op = match decode_opcode(op_byte) {
247	            Some(op) => op,
248	            None => {
249	                self.trap(4); // invalid opcode
250	                return;
251	            }
252	        };
253	
254	        if self.trace {
255	            self.trace_instruction(instr_pc, op);
256	        }
257	
258	        self.execute(op);
259	        self.instruction_count += 1;
260	    }
261	
262	    pub fn trace_instruction(&self, pc: usize, op: Opcode) {
263	        let stderr = io::stderr();
264	        let mut err = stderr.lock();
265	
266	        // Format: PC=XXXX OP=name [operands] | ESP=depth [top values] | FP=XXXX CSP=XXXX
267	        let _ = write!(err, "#{:<8} PC={:04X} ", self.instruction_count, pc);
268	
269	        // Decode operands for display (peek ahead without advancing pc)
270	        let code = &self.mem[..self.code_size];
271	        let next = self.pc; // pc already advanced past opcode
272	
273	        match op {
274	            // No operand
275	            Opcode::Halt
276	            | Opcode::Dup
277	            | Opcode::Drop
278	            | Opcode::Swap
279	            | Opcode::Over
280	            | Opcode::Add
281	            | Opcode::Sub
282	            | Opcode::Mul
283	            | Opcode::Div
284	            | Opcode::Mod
285	            | Opcode::Neg
286	            | Opcode::And
287	            | Opcode::Or
288	            | Opcode::Xor
289	            | Opcode::Not
290	            | Opcode::Shl
291	            | Opcode::Shr
292	            | Opcode::Eq
293	            | Opcode::Ne
294	            | Opcode::Lt
295	            | Opcode::Le
296	            | Opcode::Gt
297	            | Opcode::Ge
298	            | Opcode::Leave
299	            | Opcode::Load
300	            | Opcode::Store
301	            | Opcode::Loadb
302	            | Opcode::Storeb
303	            | Opcode::Memcpy
304	            | Opcode::Memset
305	            | Opcode::Memcmp
306	            | Opcode::JmpInd => {
307	                let _ = write!(err, "{:6}", format!("{op:?}").to_lowercase());
308	            }
309	            // Imm8
310	            Opcode::PushS
311	            | Opcode::Ret
312	            | Opcode::Trap
313	            | Opcode::Enter
314	            | Opcode::Loadl
315	            | Opcode::Storel
316	            | Opcode::Addrl
317	            | Opcode::Loada
318	            | Opcode::Storea
319	            | Opcode::Sys => {
320	                let imm = if next < code.len() { code[next] } else { 0 };
321	                let _ = write!(err, "{:6} {}", format!("{op:?}").to_lowercase(), imm);
322	            }
323	            // Imm24
324	            Opcode::Push
325	            | Opcode::Jmp
326	            | Opcode::Jz
327	            | Opcode::Jnz
328	            | Opcode::Call
329	            | Opcode::Loadg
330	            | Opcode::Storeg
331	            | Opcode::Addrg => {
332	                let imm = if next + 2 < code.len() {
333	                    code[next] as u32
334	                        | ((code[next + 1] as u32) << 8)
335	                        | ((code[next + 2] as u32) << 16)
336	                } else {
337	                    0
338	                };
339	                let _ = write!(err, "{:6} 0x{:06X}", format!("{op:?}").to_lowercase(), imm);
340	            }
341	            // D8A24
342	            Opcode::Calln => {
343	                let d = if next < code.len() { code[next] } else { 0 };
344	                let a = if next + 3 < code.len() {
345	                    code[next + 1] as u32
346	                        | ((code[next + 2] as u32) << 8)
347	                        | ((code[next + 3] as u32) << 16)
348	                } else {
349	                    0
350	                };
351	                let _ = write!(err, "{:6} {} 0x{:06X}", "calln", d, a);
352	            }
353	            // Imm16
354	            Opcode::XCall => {
355	                let imm = if next + 1 < code.len() {
356	                    code[next] as u16 | ((code[next + 1] as u16) << 8)
357	                } else {
358	                    0
359	                };
360	                let _ = write!(err, "{:6} slot={}", "xcall", imm);
361	            }
362	            // D8O8
363	            Opcode::Loadn | Opcode::Storen | Opcode::XLoadg | Opcode::XStoreg => {
364	                let d = if next < code.len() { code[next] } else { 0 };
365	                let o = if next + 1 < code.len() {
366	                    code[next + 1]
367	                } else {
368	                    0
369	                };
370	                let _ = write!(err, "{:6} {} {}", format!("{op:?}").to_lowercase(), d, o);
371	            }
372	        }
373	
374	        // Stack state: show depth and top 4 values
375	        let depth = self.eval_depth();
376	        let _ = write!(err, " | ESP={}", depth);
377	        if depth > 0 {
378	            let _ = write!(err, " [");
379	            let show = depth.min(4);
380	            for i in 0..show {
381	                let addr = self.esp - (i + 1) * WORD;
382	                let val = self.read_word(addr);
383	                if i > 0 {
384	                    let _ = write!(err, ", ");
385	                }
386	                let _ = write!(err, "{}", val);
387	            }
388	            if depth > 4 {
389	                let _ = write!(err, ", ...");
390	            }
391	            let _ = write!(err, "]");
392	        }
393	
394	        let _ = write!(err, " | FP={:04X}", self.fp_vm);
395	        let _ = writeln!(err);
396	    }
