#[test]
fn trace_first_instructions() {
    let mut s = Session::new("print_int 42");
    eprintln!(
        "init: pc=0x{:06X} code_base=0x{:06X} code_end=0x{:06X} csp=0x{:06X} gp=0x{:06X}",
        s.pc, s.code_abs_base, s.code_end, s.csp, s.gp
    );
    eprintln!("unit ranges: {:?}", s.unit_abs_code_ranges);
    for i in 0..20 {
        if s.status != 0 {
            eprintln!("  halted at step {i}");
            break;
        }
        let pc_before = s.pc;
        let op = s.mem[pc_before];
        s.pc += 1;
        s.execute(op);
        eprintln!(
            "  [{i}] pc_before=0x{:06X} op=0x{:02X} -> pc=0x{:06X} esp={} status={}",
            pc_before,
            op,
            s.pc,
            (s.esp - s.eval_stack_base) / WORD,
            s.status
        );
    }
}

#[test]
fn print_int_42_runs_to_completion_with_42_in_output() {
    let mut s = Session::new("print_int 42");
    // 500 ticks * 200k batch = up to 100M instrs; OCaml interp
    // startup + evaluating a tiny expression should be well under.
    run_to_done(&mut s, 500);
    eprintln!(
        "status={} trap={} instrs={} pc=0x{:06X} esp=0x{:06X} csp=0x{:06X} fp=0x{:06X}",
        s.status, s.trap_code, s.instruction_count, s.pc, s.esp, s.csp, s.fp_vm
    );
    eprintln!("raw output: {:?}", s.output());
    assert!(
        s.is_done(),
        "session did not finish: instrs={}",
        s.instruction_count
    );
    assert!(
        s.is_halted(),
        "session trapped: {} (instrs={}, out={:?})",
        s.stop_reason(),
        s.instruction_count,
        s.output()
    );
    let cleaned = s.clean_output();
    assert!(
        cleaned.contains("42"),
        "expected '42' in cleaned output, got: {cleaned:?} (raw: {:?})",
        s.output()
    );
}

